module model_compare_counter_core #(
    parameter integer COUNT_WIDTH = 8,
    parameter integer STEP_WIDTH  = 4
) (
    input  logic                    clk,
    input  logic                    rst_n,
    input  logic                    enable,
    input  logic                    clear,
    input  logic [STEP_WIDTH-1:0]   step,
    output logic [COUNT_WIDTH-1:0]  count,
    output logic                    wrapped,
    output logic                    valid
);

    localparam [1:0] RESET  = 2'd0;
    localparam [1:0] CLEAR  = 2'd1;
    localparam [1:0] UPDATE = 2'd2;
    localparam [1:0] IDLE   = 2'd3;

    logic [1:0] state_q;
    logic [1:0] state_d;

    // FunctionalModel architectural state variables.
    logic [COUNT_WIDTH-1:0] count_q;
    logic                   wrapped_q;
    logic                   valid_q;

    // SSOT memory.instances naming retained as observable aliases.
    wire [COUNT_WIDTH-1:0] count_state_ff;
    wire                   wrapped_state_ff;
    wire                   valid_state_ff;

    // FM_UPDATE uses zero-extended addition and carry-out for wrapped pulse.
    logic [COUNT_WIDTH-1:0] step_ext;
    logic [COUNT_WIDTH:0]   sum_ext;

    // FM_* output-rule intent wires used for single-cycle COMMIT behavior.
    logic [COUNT_WIDTH-1:0] out_count;
    logic                   out_wrapped;
    logic                   out_valid;

    assign count_state_ff   = count_q;
    assign wrapped_state_ff = wrapped_q;
    assign valid_state_ff   = valid_q;

    assign step_ext = {{(COUNT_WIDTH-STEP_WIDTH){1'b0}}, step};
    assign sum_ext  = {1'b0, count_q} + {1'b0, step_ext};

    // Clear-priority transaction selection for FM_CLEAR/FM_UPDATE/FM_IDLE.
    always @(*) begin
        state_d = state_q;
        case (state_q)
            RESET: begin
                if (rst_n) state_d = IDLE;
                else       state_d = RESET;
            end
            IDLE: begin
                if (clear)       state_d = CLEAR;
                else if (enable) state_d = UPDATE;
                else             state_d = IDLE;
            end
            CLEAR:  state_d = IDLE;
            UPDATE: state_d = IDLE;
            default: state_d = RESET;
        endcase
    end

    // Output rules are evaluated from current sampled inputs/state and committed on this edge.
    // This satisfies latency=1: no extra sample stage before output commit.
    always @(*) begin
        if (clear) begin
            out_count   = {COUNT_WIDTH{1'b0}};
            out_wrapped = 1'b0;
            out_valid   = 1'b0;
        end else if (enable) begin
            out_count   = sum_ext[COUNT_WIDTH-1:0];
            out_wrapped = sum_ext[COUNT_WIDTH];
            out_valid   = 1'b1;
        end else begin
            out_count   = count_q;
            out_wrapped = 1'b0;
            out_valid   = 1'b0;
        end
    end

    // Single sequential commit process for RESET/CLEAR/UPDATE/IDLE behavior.
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state_q   <= RESET;
            count_q   <= {COUNT_WIDTH{1'b0}};
            wrapped_q <= 1'b0;
            valid_q   <= 1'b0;
        end else begin
            state_q   <= state_d;
            count_q   <= out_count;
            wrapped_q <= out_wrapped;
            valid_q   <= out_valid;
        end
    end

    // Architectural outputs map directly to the committed FM output-rule values.
    assign count   = count_q;
    assign wrapped = wrapped_q;
    assign valid   = valid_q;

endmodule

